mapper.delete:
/** CmmtBoardCmmntDao.deleteList */
delete from cmmt_board_cmmnt
where
	article_id = #{articleId}

mapper.select:
/** CmmtBoardCmmntDao.selectList_count */
select
	count(*) as cnt
from cmmt_board_cmmnt
where
	article_id = #{articleId}

/** CmmtBoardCmmntDao.selectList */
select


		,#{totalItems} + 1 - (row_number() over (order by created_dt desc)) as rn


		,row_number() over (order by created_dt) as rn

from cmmt_board_cmmnt
where
	article_id = #{articleId}
offset #{beginRowNum} -1
limit #{itemsPerPage}

mapper.insert:
/** CmmtBoardCmmntDao.insert */
insert into cmmt_board_cmmnt (
	 article_id
	,cmmnt_id
	,cmmnt
	,creator_id
	,created_dt
	,updater_id
	,updated_dt
) values (
	 #{articleId}
	,#{cmmntId}
	,#{cmmnt}
	,#{creatorId}
	,#{createdDt}
	,#{updaterId}
	,#{updatedDt}
)

mapper.select:
/** CmmtBoardCmmntDao.select */
select

from cmmt_board_cmmnt
where
	article_id = #{articleId}
	and cmmnt_id = #{cmmntId}

mapper.update:
/** CmmtBoardCmmntDao.update */
update cmmt_board_cmmnt set
	 cmmnt      = #{cmmnt}
	,creator_id = #{creatorId}
	,created_dt = #{createdDt}
	,updater_id = #{updaterId}
	,updated_dt = #{updatedDt}
where
	article_id = #{articleId}
	and cmmnt_id = #{cmmntId}

